// constants
const products = [
  {
    name: "Nike Sneakers",
    price: "$210",
    image: "https://cdn.uiable.com/block/e-commerce-7-1.png",
  },
  {
    name: "Anti-theft Backpack",
    price: "$340",
    image: "https://cdn.uiable.com/block/e-commerce-7-2.png",
  },
  {
    name: "Rain Jacket",
    price: "$210",
    image: "https://cdn.uiable.com/block/e-commerce-7-3.png",
  },
  {
    name: "Retro Sunglasses",
    price: "$340",
    image: "https://cdn.uiable.com/block/e-commerce-7-4.png",
  },
];

//  ------------------------------ | E - COMMERCE 7 | ------------------------------  //

export default function Ecommerce7() {
  return (
    <section className="py-20 sm:py-24">
      <div className="container mx-auto px-6 lg:px-8">
        <div className="mx-auto max-w-2xl text-center">
          <p className="text-lg uppercase font-medium tracking-widest text-primary">
            E-commerce
          </p>
          <h2 className="mt-2">Product You Need</h2>
        </div>

        <div className="mx-auto mt-10 grid max-w-6xl grid-cols-12 gap-6">
          {products.map((product) => (
            <article
              key={product.name}
              className="col-span-12 rounded-2xl md:col-span-6 lg:col-span-3"
            >
              <div className="relative">
                <img
                  src={product.image}
                  alt={product.name}
                  className="object-contain"
                />
                <div className="absolute inset-x-0 bottom-0 px-3 pb-3 pt-12">
                  <p className="mb-2 text-lg font-medium text-white">
                    {product.name}
                  </p>
                  <p className="text-lg text-white/85 mb-3">{product.price}</p>
                </div>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}
